:root {
  --bg-dashboard: #1e1b2e;
  --bg-card: #2a2640;
  --border-card: #3d3860;
  --text-heading: #f0eeff;
  --text-muted: #9b96c4;
  --text-label: #6e6a99;
  --accent-live: #22c97a;
  --accent-live-bg: #0e3326;
  --bar-track: #3d3860;
  --bar-delivered: #7c6ff7;
  --bar-opened: #22c97a;
  --bar-clicked: #f5a623;
  --bar-bounced: #f05b5b;
  --tag-bg: #3d3860;
  --tag-text: #c4bfee;
}

.dashboard {
  background: var(--bg-dashboard);
  border-radius: 16px;
  padding: 20px;
  width: 500px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.dashboard-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.header-left {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.campaign-label {
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-label);
}

.campaign-name {
  font-size: 20px;
  font-weight: 700;
  color: var(--text-heading);
  margin: 0;
}

.status-badge {
  background: var(--accent-live-bg);
  color: var(--accent-live);
  font-size: 12px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  padding: 5px 12px;
  border-radius: 20px;
  border: 1px solid var(--accent-live);
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 10px;
}

.stat-card {
  background: var(--bg-card);
  border: 1px solid var(--border-card);
  border-radius: 12px;
  padding: 14px 12px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.stat-value {
  font-size: 22px;
  font-weight: 700;
  color: var(--text-heading);
  line-height: 1;
}

.stat-label {
  font-size: 11px;
  font-weight: 500;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.stat-bar {
  margin-top: 8px;
  background: var(--bar-track);
  border-radius: 4px;
  height: 5px;
  width: 100%;
  overflow: hidden;
}

.stat-fill {
  height: 100%;
  border-radius: 4px;
}

.fill-delivered {
  background: var(--bar-delivered);
  width: 84%;
}

.fill-opened {
  background: var(--bar-opened);
  width: 62%;
}

.fill-clicked {
  background: var(--bar-clicked);
  width: 28%;
}

.fill-bounced {
  background: var(--bar-bounced);
  width: 10%;
}

.footer-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: 4px;
  border-top: 1px solid var(--border-card);
}

.audience-info {
  display: flex;
  align-items: center;
  gap: 7px;
}

.audience-icon {
  font-size: 14px;
  color: var(--text-muted);
}

.audience-text {
  font-size: 13px;
  font-weight: 500;
  color: var(--text-muted);
}

.footer-tags {
  display: flex;
  gap: 6px;
}

.tag {
  background: var(--tag-bg);
  color: var(--tag-text);
  font-size: 11px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 6px;
  letter-spacing: 0.03em;
}
